const express = require('express');
const router = express.Router();

// Simulated database layer - replace with your actual database/ORM
const db = require('../db');

// Authentication middleware (assumed to be applied before these routes)
// req.user is populated with verified server-side session data: { id, companyId, role }

// Middleware to ensure user is authenticated
function requireAuth(req, res, next) {
  if (!req.user || !req.user.id || !req.user.companyId) {
    return res.status(401).json({ error: 'Authentication required' });
  }
  next();
}

// Middleware to ensure user has admin role (verified server-side, never from client input)
function requireAdmin(req, res, next) {
  if (req.user.role !== 'admin') {
    return res.status(403).json({ error: 'Admin access required' });
  }
  next();
}

// Allowlisted fields for document creation
const ALLOWED_CREATE_FIELDS = ['title', 'content', 'category', 'tags'];

// Allowlisted fields for document update
const ALLOWED_UPDATE_FIELDS = ['title', 'content', 'category', 'tags'];

// Helper: pick only allowed fields from an object
function pickAllowedFields(source, allowedFields) {
  const result = {};
  for (const field of allowedFields) {
    if (source.hasOwnProperty(field)) {
      result[field] = source[field];
    }
  }
  return result;
}

// GET /api/documents - List all documents for the authenticated user's company
router.get('/documents', requireAuth, async (req, res) => {
  try {
    // Always scope queries by the authenticated user's companyId from the server-side session.
    // Never use a companyId or tenant ID provided by the client.
    const documents = await db.documents.findAll({
      where: {
        companyId: req.user.companyId
      },
      select: ['id', 'title', 'content', 'category', 'tags', 'createdBy', 'createdAt', 'updatedAt']
    });

    return res.status(200).json({ documents });
  } catch (error) {
    console.error('Error listing documents:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

// GET /api/documents/:documentId - View a specific document
router.get('/documents/:documentId', requireAuth, async (req, res) => {
  try {
    const { documentId } = req.params;

    // Load the resource scoped by BOTH the document ID and the authenticated user's companyId.
    // This prevents IDOR attacks where a user tries to access another company's document.
    const document = await db.documents.findOne({
      where: {
        id: documentId,
        companyId: req.user.companyId
      },
      select: ['id', 'title', 'content', 'category', 'tags', 'createdBy', 'createdAt', 'updatedAt']
    });

    if (!document) {
      // Return 404 rather than 403 to avoid leaking information about document existence
      return res.status(404).json({ error: 'Document not found' });
    }

    return res.status(200).json({ document });
  } catch (error) {
    console.error('Error fetching document:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

// POST /api/documents - Create a new document
router.post('/documents', requireAuth, async (req, res) => {
  try {
    // Only pick allowlisted fields from user input - never mass-assign
    const documentData = pickAllowedFields(req.body, ALLOWED_CREATE_FIELDS);

    if (!documentData.title || typeof documentData.title !== 'string' || documentData.title.trim().length === 0) {
      return res.status(400).json({ error: 'Title is required' });
    }

    if (documentData.content && typeof documentData.content !== 'string') {
      return res.status(400).json({ error: 'Content must be a string' });
    }

    if (documentData.category && typeof documentData.category !== 'string') {
      return res.status(400).json({ error: 'Category must be a string' });
    }

    if (documentData.tags) {
      if (!Array.isArray(documentData.tags) || !documentData.tags.every(t => typeof t === 'string')) {
        return res.status(400).json({ error: 'Tags must be an array of strings' });
      }
    }

    // Server-side assignment of ownership fields - never trust client-provided values
    const newDocument = await db.documents.create({
      ...documentData,
      companyId: req.user.companyId,  // Always from authenticated session
      createdBy: req.user.id,          // Always from authenticated session
      createdAt: new Date(),
      updatedAt: new Date()
    });

    return res.status(201).json({ document: newDocument });
  } catch (error) {
    console.error('Error creating document:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

// PUT /api/documents/:documentId - Update a document
router.put('/documents/:documentId', requireAuth, async (req, res) => {
  try {
    const { documentId } = req.params;

    // Load the resource scoped by both document ID and the authenticated user's companyId
    const existingDocument = await db.documents.findOne({
      where: {
        id: documentId,
        companyId: req.user.companyId
      }
    });

    if (!existingDocument) {
      return res.status(404).json({ error: 'Document not found' });
    }

    // Object-level authorization: only the creator or an admin can update
    if (existingDocument.createdBy !== req.user.id && req.user.role !== 'admin') {
      return res.status(403).json({ error: 'You do not have permission to update this document' });
    }

    // Only pick allowlisted fields - prevents mass assignment of privileged fields
    // like companyId, createdBy, role, etc.
    const updateData = pickAllowedFields(req.body, ALLOWED_UPDATE_FIELDS);

    if (Object.keys(updateData).length === 0) {
      return res.status(400).json({ error: 'No valid fields provided for update' });
    }

    // Validate fields if provided
    if (updateData.title !== undefined) {
      if (typeof updateData.title !== 'string' || updateData.title.trim().length === 0) {
        return res.status(400).json({ error: 'Title must be a non-empty string' });
      }
    }

    if (updateData.content !== undefined && typeof updateData.content !== 'string') {
      return res.status(400).json({ error: 'Content must be a string' });
    }

    if (updateData.category !== undefined && typeof updateData.category !== 'string') {
      return res.status(400).json({ error: 'Category must be a string' });
    }

    if (updateData.tags !== undefined) {
      if (!Array.isArray(updateData.tags) || !updateData.tags.every(t => typeof t === 'string')) {
        return res.status(400).json({ error: 'Tags must be an array of strings' });
      }
    }

    // Set server-controlled metadata
    updateData.updatedAt = new Date();

    const updatedDocument = await db.documents.update({
      where: {
        id: documentId,
        companyId: req.user.companyId  // Re-scope to prevent race conditions
      },
      data: updateData
    });

    return res.status(200).json({ document: updatedDocument });
  } catch (error) {
    console.error('Error updating document:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

// DELETE /api/documents/:documentId - Delete a document
router.delete('/documents/:documentId', requireAuth, async (req, res) => {
  try {
    const { documentId } = req.params;

    // Load the resource scoped by both document ID and the authenticated user's companyId
    const existingDocument = await db.documents.findOne({
      where: {
        id: documentId,
        companyId: req.user.companyId
      }
    });

    if (!existingDocument) {
      return res.status(404).json({ error: 'Document not found' });
    }

    // Object-level authorization: only the creator or an admin can delete
    if (existingDocument.createdBy !== req.user.id && req.user.role !== 'admin') {
      return res.status(403).json({ error: 'You do not have permission to delete this document' });
    }

    await db.documents.delete({
      where: {
        id: documentId,
        companyId: req.user.companyId  // Always re-scope by tenant
      }
    });

    return res.status(200).json({ message: 'Document deleted successfully' });
  } catch (error) {
    console.error('Error deleting document:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

